// frontend/src/components/Analytics.js
import React, { useState, useEffect } from 'react';
import { getMyHistory } from '../services/api';

export default function Analytics() {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getMyHistory()
      .then(setHistory)
      .catch(() => setHistory([]))
      .finally(() => setLoading(false));
  }, []);

  // Compute stats
  const totalVisits   = history.length;
  const totalSpent    = history.reduce((s, h) => s + (parseFloat(h.amount_spent) || 0), 0);
  const avgSpent      = totalVisits > 0 ? totalSpent / history.filter(h => h.amount_spent).length || 0 : 0;
  const uniquePlaces  = new Set(history.map(h => h.place_id)).size;

  // Category breakdown
  const catCount = history.reduce((acc, h) => {
    acc[h.category] = (acc[h.category] || 0) + 1;
    return acc;
  }, {});

  // Recent spending (last 7 visits)
  const recentSpending = history.slice(0, 7).reverse().map((h, i) => ({
    label: new Date(h.checked_in_at).toLocaleDateString('en-IN', { month: 'short', day: 'numeric' }),
    value: parseFloat(h.amount_spent) || 0,
    name: h.place_name,
  }));

  const maxSpend = Math.max(...recentSpending.map(r => r.value), 1);

  const CAT_COLORS = { mall: '#1D9E75', cafe: '#d4a017', gym: '#3498db', restaurant: '#e74c3c' };
  const CAT_ICONS  = { mall: '🛍️', cafe: '☕', gym: '💪', restaurant: '🍽️' };

  if (loading) return (
    <div style={{ textAlign: 'center', padding: '60px', color: '#bbb' }}>
      <div style={{ fontSize: '32px', marginBottom: '12px' }}>📊</div>
      Loading analytics...
    </div>
  );

  return (
    <div>
      {/* Stats cards */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '12px', marginBottom: '24px' }}>
        {[
          { label: 'Total Visits',    value: totalVisits,              icon: '📍', color: '#1D9E75' },
          { label: 'Total Spent',     value: `₹${Math.round(totalSpent)}`, icon: '💰', color: '#d4a017' },
          { label: 'Avg Per Visit',   value: `₹${Math.round(avgSpent)}`,   icon: '📊', color: '#3498db' },
          { label: 'Places Visited',  value: uniquePlaces,             icon: '🗺️', color: '#9b59b6' },
        ].map(s => (
          <div key={s.label} style={{
            background: '#fff', borderRadius: '16px', padding: '18px',
            border: '1.5px solid #f0f0f0', textAlign: 'center',
          }}>
            <div style={{ fontSize: '28px', marginBottom: '8px' }}>{s.icon}</div>
            <div style={{ fontSize: '22px', fontWeight: '800', color: s.color }}>{s.value}</div>
            <div style={{ fontSize: '11px', color: '#bbb', marginTop: '4px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>{s.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '24px' }}>
        {/* Spending chart */}
        <div style={{ background: '#fff', borderRadius: '16px', padding: '20px', border: '1.5px solid #f0f0f0' }}>
          <h3 style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e', marginBottom: '16px', margin: '0 0 16px' }}>
            Recent Spending
          </h3>
          {recentSpending.length === 0 ? (
            <p style={{ color: '#bbb', fontSize: '13px', textAlign: 'center', padding: '20px 0' }}>No spending data yet</p>
          ) : (
            <div style={{ display: 'flex', alignItems: 'flex-end', gap: '8px', height: '120px' }}>
              {recentSpending.map((r, i) => (
                <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px' }}>
                  <div style={{ fontSize: '10px', color: '#1D9E75', fontWeight: '700' }}>
                    {r.value > 0 ? `₹${r.value}` : ''}
                  </div>
                  <div style={{
                    width: '100%', borderRadius: '6px 6px 0 0',
                    background: r.value > 0 ? 'linear-gradient(180deg, #1D9E75, #0f6e56)' : '#f0f0f0',
                    height: `${Math.max((r.value / maxSpend) * 90, r.value > 0 ? 8 : 4)}px`,
                    transition: 'height .5s ease',
                  }} />
                  <div style={{ fontSize: '9px', color: '#bbb', textAlign: 'center' }}>{r.label}</div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Category breakdown */}
        <div style={{ background: '#fff', borderRadius: '16px', padding: '20px', border: '1.5px solid #f0f0f0' }}>
          <h3 style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e', margin: '0 0 16px' }}>
            Visit by Category
          </h3>
          {Object.keys(catCount).length === 0 ? (
            <p style={{ color: '#bbb', fontSize: '13px', textAlign: 'center', padding: '20px 0' }}>No visits yet</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {Object.entries(catCount).sort((a, b) => b[1] - a[1]).map(([cat, count]) => (
                <div key={cat}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '5px' }}>
                    <span style={{ fontSize: '13px', color: '#555' }}>
                      {CAT_ICONS[cat] || '📍'} {cat.charAt(0).toUpperCase() + cat.slice(1)}
                    </span>
                    <span style={{ fontSize: '13px', fontWeight: '700', color: CAT_COLORS[cat] || '#888' }}>{count}</span>
                  </div>
                  <div style={{ height: '6px', background: '#f0f0f0', borderRadius: '4px', overflow: 'hidden' }}>
                    <div style={{
                      height: '100%', borderRadius: '4px',
                      background: CAT_COLORS[cat] || '#888',
                      width: `${(count / totalVisits) * 100}%`,
                    }} />
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* History table */}
      <div style={{ background: '#fff', borderRadius: '16px', padding: '20px', border: '1.5px solid #f0f0f0' }}>
        <h3 style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e', margin: '0 0 16px' }}>Visit History</h3>
        {history.length === 0 ? (
          <p style={{ color: '#bbb', fontSize: '13px', textAlign: 'center', padding: '20px 0' }}>
            No visits recorded yet. Check in at a place to get started!
          </p>
        ) : (
          history.map(h => (
            <div key={h.id} style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              padding: '12px 0', borderBottom: '1px solid #f5f5f5',
            }}>
              <div>
                <div style={{ fontWeight: '600', fontSize: '14px', color: '#1a1a2e' }}>{h.place_name}</div>
                <div style={{ fontSize: '12px', color: '#bbb', marginTop: '2px' }}>
                  {h.category} · {new Date(h.checked_in_at).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}
                  {h.checked_out_at ? ` · ${Math.round((new Date(h.checked_out_at) - new Date(h.checked_in_at)) / 60000)} min` : ' · Active'}
                </div>
              </div>
              <div style={{
                fontWeight: '800', fontSize: '16px',
                color: h.amount_spent ? '#1D9E75' : '#ddd',
              }}>
                {h.amount_spent ? `₹${Math.round(h.amount_spent)}` : '—'}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
